/*
 * @ignore
 * @method
 * @description Connects to a websocket channel
 * @param {string} name name of the channel
 * @param {string} messageHash string to look up in handler
 * @param {string[]|float[]} request endpoint parameters
 * @param {object} [params] extra parameters specific to the p2b api
 * @returns {object} data from the websocket stream
 */
    pub async fn subscribe(&mut self, mut name: Value, mut messageHash: Value, mut request: Value, optional_args: &[Value]) -> Value {
        let mut params = get_arg(optional_args, 0, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut url: Value = get_value(&get_value(&self.urls, &Value::Str("api".to_string())), &Value::Str("ws".to_string()));
        let mut subscribe: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("method".to_string(), name.clone());
                m.insert("params".to_string(), request.clone());
                m.insert("id".to_string(), self.milliseconds());
            m
        });
        let mut query: Value = self.extend(subscribe.clone(), &[params.clone()]);
        return self.watch(url.clone(), messageHash.clone(), &[query.clone(), messageHash.clone()]).await;

    Value::Null
}

